import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;

@Service
class NaiveReviewLoader {
    private final AtomicInteger queryCount = new AtomicInteger(0);

    // N+1 pattern: called once per product
    public List<String> findByProductId(String productId) {
        queryCount.incrementAndGet(); // each call = 1 DB query
        return List.of("Review for " + productId + " (4 stars)");
    }

    public int getQueryCount() { return queryCount.get(); }
    public void reset() { queryCount.set(0); }
}

@Service
class BatchReviewLoader {
    private final AtomicInteger queryCount = new AtomicInteger(0);

    // DataLoader pattern: called ONCE with all product IDs
    public Map<String, List<String>> findByProductIdIn(List<String> productIds) {
        queryCount.incrementAndGet(); // always 1 query regardless of how many IDs
        Map<String, List<String>> result = new HashMap<>();
        for (String id : productIds) {
            result.put(id, List.of("Review for " + id + " (4 stars)"));
        }
        return result;
    }

    public int getQueryCount() { return queryCount.get(); }
    public void reset() { queryCount.set(0); }
}

@SpringBootTest
class NPlus1DemoTest {
    @Autowired NaiveReviewLoader naive;
    @Autowired BatchReviewLoader batch;

    @BeforeEach void reset() { naive.reset(); batch.reset(); }

    @Test void naive_causesNPlus1() {
        List<String> productIds = List.of("P1", "P2", "P3", "P4", "P5",
                                           "P6", "P7", "P8", "P9", "P10");
        // Simulate @SchemaMapping called once per product:
        productIds.forEach(naive::findByProductId);

        assertEquals(10, naive.getQueryCount(), "Naive: 10 products = 10 DB queries (N+1 = 11 total)");
    }

    @Test void batch_usesOneQuery() {
        List<String> productIds = List.of("P1", "P2", "P3", "P4", "P5",
                                           "P6", "P7", "P8", "P9", "P10");
        // Simulate @BatchMapping: one call with all IDs:
        batch.findByProductIdIn(productIds);

        assertEquals(1, batch.getQueryCount(), "Batch: 10 products = 1 DB query (SELECT...IN)");
    }
}

import org.springframework.graphql.data.method.annotation.BatchMapping;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.Collectors;

record Payment(String id, String merchantId, long amountPaise) {}
record Merchant(String id, String name, String gstIn) {}

@Service
class MerchantRepository {
    private final AtomicInteger queryCount = new AtomicInteger(0);
    private final Map<String, Merchant> merchants = Map.of(
        "MRC-001", new Merchant("MRC-001", "Flipkart", "GST-001"),
        "MRC-002", new Merchant("MRC-002", "Zomato", "GST-002"),
        "MRC-003", new Merchant("MRC-003", "Swiggy", "GST-003")
    );

    // ONE batch query (SELECT * FROM merchants WHERE id IN (?))
    public List<Merchant> findByIdIn(List<String> ids) {
        queryCount.incrementAndGet();
        return ids.stream()
            .map(merchants::get)
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }

    public int getQueryCount() { return queryCount.get(); }
}

@Controller
class PaymentResolver {
    private final MerchantRepository repo;
    PaymentResolver(MerchantRepository r) { repo = r; }

    // @BatchMapping: receives ALL payments at once, returns Map<Payment, Merchant>
    @BatchMapping
    public Map<Payment, Merchant> merchant(List<Payment> payments) {
        List<String> merchantIds = payments.stream()
            .map(Payment::merchantId)
            .distinct()
            .collect(Collectors.toList());

        // ONE DB query for all merchants:
        List<Merchant> merchants = repo.findByIdIn(merchantIds);
        Map<String, Merchant> byId = merchants.stream()
            .collect(Collectors.toMap(Merchant::id, m -> m));

        // Map each payment to its merchant:
        return payments.stream()
            .collect(Collectors.toMap(
                p -> p,
                p -> byId.getOrDefault(p.merchantId(),
                    new Merchant("UNKNOWN", "Unknown Merchant", ""))
            ));
    }
}

@SpringBootTest
class BatchMappingTest {
    @Autowired PaymentResolver resolver;
    @Autowired MerchantRepository repo;

    @Test void batchMapping_oneQuery() {
        List<Payment> payments = List.of(
            new Payment("PAY-1", "MRC-001", 5000L),
            new Payment("PAY-2", "MRC-002", 3000L),
            new Payment("PAY-3", "MRC-001", 1500L), // same merchant as PAY-1
            new Payment("PAY-4", "MRC-003", 8000L),
            new Payment("PAY-5", "MRC-002", 2000L)  // same as PAY-2
        );

        Map<Payment, Merchant> result = resolver.merchant(payments);

        assertEquals(5, result.size()); // one entry per payment
        assertEquals(1, repo.getQueryCount()); // ONE batch query (not 5!)
        assertEquals("Flipkart", result.get(payments.get(0)).name());
        assertEquals("Zomato", result.get(payments.get(1)).name());
        assertEquals("Flipkart", result.get(payments.get(2)).name()); // same merchant reused
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class CachingDataLoader {
    // DataLoader caches results within a single request:
    private final Map<String, List<String>> cache = new HashMap<>();
    private int dbHits = 0;
    private int cacheHits = 0;

    public List<String> load(String productId) {
        if (cache.containsKey(productId)) {
            cacheHits++;  // DataLoader cache hit: no DB call
            return cache.get(productId);
        }
        // Cache miss: go to DB
        dbHits++;
        List<String> reviews = List.of("Review1 for " + productId, "Review2 for " + productId);
        cache.put(productId, reviews);
        return reviews;
    }

    // Batch load (actual DataLoader batches into one DB call):
    public Map<String, List<String>> loadBatch(List<String> productIds) {
        Map<String, List<String>> result = new HashMap<>();
        List<String> uncached = new ArrayList<>();

        for (String id : productIds) {
            if (cache.containsKey(id)) {
                cacheHits++;
                result.put(id, cache.get(id));
            } else {
                uncached.add(id);
            }
        }
        if (!uncached.isEmpty()) {
            dbHits++; // ONE batch query for all uncached
            for (String id : uncached) {
                List<String> reviews = List.of("Review for " + id);
                cache.put(id, reviews);
                result.put(id, reviews);
            }
        }
        return result;
    }

    public int getDbHits() { return dbHits; }
    public int getCacheHits() { return cacheHits; }
    public void reset() { cache.clear(); dbHits = 0; cacheHits = 0; }
}

@SpringBootTest
class DataLoaderCachingTest {
    @Autowired CachingDataLoader loader;

    @BeforeEach void reset() { loader.reset(); }

    @Test void firstLoad_isCacheMiss() {
        loader.load("P1");
        assertEquals(1, loader.getDbHits());
        assertEquals(0, loader.getCacheHits());
    }
    @Test void sameId_twice_isCacheHit() {
        loader.load("P2");
        loader.load("P2"); // same ID again → cache hit!
        assertEquals(1, loader.getDbHits());   // only 1 DB call
        assertEquals(1, loader.getCacheHits()); // 1 cache hit
    }
    @Test void differentId_isCacheMiss() {
        loader.load("P3");
        loader.load("P4"); // different ID → new DB call
        assertEquals(2, loader.getDbHits());
        assertEquals(0, loader.getCacheHits());
    }
}

import org.springframework.graphql.data.method.annotation.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
