import java.util.concurrent.atomic.AtomicInteger;
import java.util.stream.Collectors;

record FlipProduct(String id, String name, String category) {}
record FlipReview(String productId, String reviewer, int rating, String text) {}

@Service
class FlipReviewRepo {
    private final AtomicInteger queries = new AtomicInteger(0);
    public List<FlipReview> findByProductIdIn(List<String> ids) {
        queries.incrementAndGet();
        List<FlipReview> all = new ArrayList<>();
        for (String id : ids) {
            all.add(new FlipReview(id, "Raj", 5, "Excellent product!"));
            all.add(new FlipReview(id, "Priya", 4, "Good value."));
        }
        return all;
    }
    int getQueries() { return queries.get(); }
}

@Controller
class FlipProductController {
    private final FlipReviewRepo repo;
    FlipProductController(FlipReviewRepo r) { repo = r; }

    @QueryMapping
    public List<FlipProduct> products() {
        return List.of(
            new FlipProduct("FP-1", "iPhone 15", "Electronics"),
            new FlipProduct("FP-2", "Samsung TV", "Electronics"),
            new FlipProduct("FP-3", "Running Shoes", "Sports"),
            new FlipProduct("FP-4", "Laptop Bag", "Accessories"),
            new FlipProduct("FP-5", "Water Bottle", "Sports")
        );
    }

    @BatchMapping
    public Map<FlipProduct, List<FlipReview>> reviews(List<FlipProduct> products) {
        List<String> ids = products.stream().map(FlipProduct::id).collect(Collectors.toList());
        List<FlipReview> reviews = repo.findByProductIdIn(ids); // ONE query
        return products.stream().collect(Collectors.toMap(
            p -> p,
            p -> reviews.stream().filter(r -> r.productId().equals(p.id())).collect(Collectors.toList())
        ));
    }
}

@SpringBootTest
class FlipBatchMappingTest {
    @Autowired FlipProductController ctrl;
    @Autowired FlipReviewRepo repo;

    @Test void batchMapping_oneQuery() {
        List<FlipProduct> products = ctrl.products();
        Map<FlipProduct, List<FlipReview>> reviews = ctrl.reviews(products);
        assertEquals(1, repo.getQueries()); // ONE batch query for all 5 products
    }
    @Test void allProducts_haveReviews() {
        List<FlipProduct> products = ctrl.products();
        Map<FlipProduct, List<FlipReview>> reviews = ctrl.reviews(products);
        products.forEach(p -> assertFalse(reviews.get(p).isEmpty()));
    }
}

