@Service
class ZTradeRepo {
    final AtomicInteger q = new AtomicInteger(0);
    public List<ZTrade> findByOrderIdIn(List<String> ids) {
        q.incrementAndGet();
        List<ZTrade> all = new ArrayList<>();
        for (String id : ids) all.add(new ZTrade("T-"+id, id, "NSE:RELIANCE", 10));
        return all;
    }
}

@Service
class ZInstrumentRepo {
    final AtomicInteger q = new AtomicInteger(0);
    public List<ZInstrument> findByIdIn(List<String> ids) {
        q.incrementAndGet();
        return ids.stream().distinct().map(id -> new ZInstrument(id, id.replace("NSE:",""), "NSE")).collect(Collectors.toList());
    }
