@Controller
class ZerodhaOrderController {
    private final ZTradeRepo tradeRepo;
    private final ZInstrumentRepo instrRepo;
    ZerodhaOrderController(ZTradeRepo t, ZInstrumentRepo i) { tradeRepo=t; instrRepo=i; }

    @QueryMapping
    public List<ZOrder> orders() {
        return List.of(new ZOrder("O1","COMPLETE"), new ZOrder("O2","PENDING"), new ZOrder("O3","COMPLETE"));
    }

    @BatchMapping
    public Map<ZOrder, List<ZTrade>> trades(List<ZOrder> orders) {
        List<String> ids = orders.stream().map(ZOrder::id).collect(Collectors.toList());
        List<ZTrade> trades = tradeRepo.findByOrderIdIn(ids); // 1 query
        return orders.stream().collect(Collectors.toMap(o->o,
            o->trades.stream().filter(t->t.orderId().equals(o.id())).collect(Collectors.toList())));
    }

    @BatchMapping
    public Map<ZTrade, ZInstrument> instrument(List<ZTrade> trades) {
        List<String> instrIds = trades.stream().map(ZTrade::instrumentId).distinct().collect(Collectors.toList());
        List<ZInstrument> instruments = instrRepo.findByIdIn(instrIds); // 1 query
        Map<String,ZInstrument> byId = instruments.stream().collect(Collectors.toMap(ZInstrument::id, i->i));
        return trades.stream().collect(Collectors.toMap(t->t,
            t->byId.getOrDefault(t.instrumentId(), new ZInstrument("UNK","UNKNOWN",""))));
    }
}

@SpringBootTest
class NestedBatchTest {
    @Autowired ZerodhaOrderController ctrl;
    @Autowired ZTradeRepo tradeRepo;
    @Autowired ZInstrumentRepo instrRepo;

    @Test void threeLevel_threeQueries() {
        List<ZOrder> orders = ctrl.orders();                    // query 1
        Map<ZOrder,List<ZTrade>> trades = ctrl.trades(orders); // query 2
        List<ZTrade> allTrades = trades.values().stream().flatMap(Collection::stream).collect(Collectors.toList());
        ctrl.instrument(allTrades);                             // query 3

        assertEquals(1, tradeRepo.q.get(), "trades: 1 batch query");
        assertEquals(1, instrRepo.q.get(), "instruments: 1 batch query");
        // Total: 3 queries (orders + trades + instruments)
        // Without batch: 1 + 3 + N-trades = many more
    }
}

