import org.dataloader.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.Collectors;

record ReviewSummary(String productId, int avgRating, int count) {}

@Service
class ReviewDataLoaderFactory {
    private final ReviewBatchService batchService;
    ReviewDataLoaderFactory(ReviewBatchService b) { batchService = b; }

    // Create a DataLoader: input=List<String productId>, output=List<ReviewSummary>
    public DataLoader<String, ReviewSummary> createReviewLoader() {
        BatchLoader<String, ReviewSummary> batchLoader = productIds -> {
            // Called ONCE with all collected product IDs:
            return CompletableFuture.supplyAsync(() -> {
                Map<String, ReviewSummary> summaries = batchService.loadSummaries(productIds);
                // IMPORTANT: order must match input order!
                return productIds.stream()
                    .map(id -> summaries.getOrDefault(id, new ReviewSummary(id, 0, 0)))
                    .collect(Collectors.toList());
            });
        };

        return DataLoaderFactory.newDataLoader(batchLoader);
    }
}

@Service
class ReviewBatchService {
    int callCount = 0;

    public Map<String, ReviewSummary> loadSummaries(List<String> productIds) {
        callCount++; // should be called once!
        return productIds.stream().collect(Collectors.toMap(
            id -> id,
            id -> new ReviewSummary(id, 4, 23) // simulated summary
        ));
    }
}

@SpringBootTest
class DataLoaderTest {
    @Autowired ReviewDataLoaderFactory factory;
    @Autowired ReviewBatchService batchSvc;

    @Test void dataLoader_created() {
        DataLoader<String, ReviewSummary> loader = factory.createReviewLoader();
        assertNotNull(loader);
    }
    @Test void batchLoader_batchesCorrectly() throws Exception {
        DataLoader<String, ReviewSummary> loader = factory.createReviewLoader();
        // Schedule multiple loads (normally GraphQL does this):
        CompletableFuture<ReviewSummary> f1 = loader.load("P1");
        CompletableFuture<ReviewSummary> f2 = loader.load("P2");
        CompletableFuture<ReviewSummary> f3 = loader.load("P3");
        loader.dispatch(); // triggers batch call with [P1, P2, P3]
        ReviewSummary s1 = f1.get(1, TimeUnit.SECONDS);
        assertEquals("P1", s1.productId());
        assertEquals(1, batchSvc.callCount, "Batch service called once for all 3 IDs");
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@Service
class QueryComplexityAnalyzer {
    private static final int MAX_COMPLEXITY = 100;

    // Simplified complexity: depth × breadth
    public int calculateComplexity(int depth, int breadth) {
        // Each level doubles cost: 1 + 2 + 4 + ... = 2^depth - 1 × breadth
        return (int)(Math.pow(2, depth) - 1) * breadth;
    }

    public boolean isAllowed(int depth, int breadth) {
        return calculateComplexity(depth, breadth) <= MAX_COMPLEXITY;
    }

    // Field-by-field complexity:
    public int fieldComplexity(String fieldName, int multiplier) {
        return switch (fieldName) {
            case "products" -> 1 * multiplier;
            case "reviews" -> 3 * multiplier; // expensive: list field
            case "merchants" -> 2 * multiplier;
            case "id", "name", "status" -> 0; // scalar: free
            default -> 1 * multiplier;
        };
    }
}

@SpringBootTest
class QueryComplexityTest {
    @Autowired QueryComplexityAnalyzer analyzer;

    @Test void simpleQuery_allowed() {
        // products { id name } — depth=1, breadth=10
        int complexity = analyzer.calculateComplexity(1, 10);
        assertTrue(analyzer.isAllowed(1, 10));
        // complexity = (2^1 - 1) × 10 = 10: well within limit
    }
    @Test void deepNesting_rejected() {
        // products → orders → trades → instruments (depth=4, breadth=10)
        assertFalse(analyzer.isAllowed(4, 10));
        // complexity = (2^4 - 1) × 10 = 150 > 100
    }
    @Test void highMultiplier_rejected() {
        // products(limit:200) { reviews } (depth=2, breadth=200)
        assertFalse(analyzer.isAllowed(2, 200));
        // complexity = (2^2 - 1) × 200 = 600 > 100
    }
}

