@Service
class PerformanceComparator {
    static final int MS_PER_QUERY = 5;

    // Naive N+1 simulation:
    record NaiveResult(int queryCount, long latencyMs) {}
    public NaiveResult runNaive(int productCount) {
        AtomicInteger q = new AtomicInteger(0);
        // 1 query for products list:
        q.incrementAndGet();
        // N queries for reviews (one per product):
        for (int i = 0; i < productCount; i++) q.incrementAndGet();
        return new NaiveResult(q.get(), (long)q.get() * MS_PER_QUERY);
    }

    // Batch simulation:
    record BatchResult(int queryCount, long latencyMs) {}
    public BatchResult runBatch(int productCount) {
        // 1 query for products + 1 batch query for all reviews:
        int q = 2;
        return new BatchResult(q, (long)q * MS_PER_QUERY);
    }

    public double speedupFactor(NaiveResult naive, BatchResult batch) {
        return (double)naive.latencyMs() / batch.latencyMs();
    }
}

@SpringBootTest
class DataLoaderPerfTest {
    @Autowired PerformanceComparator comparator;

    @Test void naive_51queries_for50products() {
        var result = comparator.runNaive(50);
        assertEquals(51, result.queryCount()); // 1 + 50
        assertEquals(255L, result.latencyMs()); // 51 × 5ms
    }
    @Test void batch_2queries_for50products() {
        var result = comparator.runBatch(50);
        assertEquals(2, result.queryCount());
        assertEquals(10L, result.latencyMs()); // 2 × 5ms
    }
    @Test void speedup_greaterThan10x() {
        var naive = comparator.runNaive(50);
        var batch = comparator.runBatch(50);
        double speedup = comparator.speedupFactor(naive, batch);
        assertTrue(speedup > 10, "DataLoader should be >10x faster: " + speedup + "x");
        // 255ms / 10ms = 25.5× speedup
    }
}

