import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class PartialFailureBatchLoader {

    public record LoadResult(String id, Object value, String error) {
        boolean isSuccess() { return error == null; }
        static LoadResult success(String id, Object v) { return new LoadResult(id, v, null); }
        static LoadResult failure(String id, String err) { return new LoadResult(id, null, err); }
    }

    // Simulated batch: even-numbered IDs fail
    public List<LoadResult> loadBatch(List<String> ids) {
        List<LoadResult> results = new ArrayList<>();
        for (String id : ids) {
            try {
                int num = Integer.parseInt(id.replace("P", ""));
                if (num % 2 == 0) {
                    throw new RuntimeException("Simulated failure for product " + id);
                }
                results.add(LoadResult.success(id, "Data for " + id));
            } catch (NumberFormatException e) {
                results.add(LoadResult.success(id, "Data for " + id));
            } catch (RuntimeException e) {
                results.add(LoadResult.failure(id, e.getMessage()));
            }
        }
        return results;
    }

    public long countSuccesses(List<LoadResult> results) {
        return results.stream().filter(LoadResult::isSuccess).count();
    }

    public long countFailures(List<LoadResult> results) {
        return results.stream().filter(r -> !r.isSuccess()).count();
    }
}

@SpringBootTest
class PartialFailureTest {
    @Autowired PartialFailureBatchLoader loader;

    @Test void allOdd_allSucceed() {
        var results = loader.loadBatch(List.of("P1", "P3", "P5"));
        assertEquals(3, loader.countSuccesses(results));
        assertEquals(0, loader.countFailures(results));
    }
    @Test void mixedIds_partialFailure() {
        var results = loader.loadBatch(List.of("P1", "P2", "P3", "P4"));
        // P1, P3 succeed; P2, P4 fail:
        assertEquals(2, loader.countSuccesses(results));
        assertEquals(2, loader.countFailures(results));
        // Failures have error messages:
        assertTrue(results.stream().filter(r -> !r.isSuccess())
            .allMatch(r -> r.error() != null && !r.error().isBlank()));
    }
    @Test void allEven_allFail() {
        var results = loader.loadBatch(List.of("P2", "P4", "P6"));
        assertEquals(0, loader.countSuccesses(results));
        assertEquals(3, loader.countFailures(results));
    }
}

