record SOrder(String id,String status){}
record SPayment(String id,String orderId,String merchantId,long amt){}
record SMerchant(String id,String name){}

@Service class SPaymentRepo{
    final AtomicInteger q=new AtomicInteger(0);
    List<SPayment> findByOrderIdIn(List<String> ids){
        q.incrementAndGet();
        List<SPayment> all=new ArrayList<>();
        for(String id:ids){all.add(new SPayment("PAY-"+id,id,"MRC-1",5000L));all.add(new SPayment("PAY2-"+id,id,"MRC-2",3000L));}
        return all;
    }
}

@Service class SMerchantRepo{
    final AtomicInteger q=new AtomicInteger(0);
    List<SMerchant> findByIdIn(List<String> ids){
        q.incrementAndGet();
        Map<String,SMerchant> data=Map.of("MRC-1",new SMerchant("MRC-1","Flipkart"),"MRC-2",new SMerchant("MRC-2","Amazon"));
        return ids.stream().distinct().map(data::get).filter(Objects::nonNull).collect(Collectors.toList());
    }
}

@Controller class SynthOrderController{
    private final SPaymentRepo pr;private final SMerchantRepo mr;
    SynthOrderController(SPaymentRepo p,SMerchantRepo m){pr=p;mr=m;}

    @QueryMapping List<SOrder> orders(){return List.of(new SOrder("O1","DONE"),new SOrder("O2","DONE"),new SOrder("O3","PENDING"));}

    @BatchMapping Map<SOrder,List<SPayment>> payments(List<SOrder> orders){
        List<String> ids=orders.stream().map(SOrder::id).collect(Collectors.toList());
        List<SPayment> all=pr.findByOrderIdIn(ids);
        return orders.stream().collect(Collectors.toMap(o->o,o->all.stream().filter(p->p.orderId().equals(o.id())).collect(Collectors.toList())));
    }

    @BatchMapping Map<SPayment,SMerchant> merchant(List<SPayment> payments){
        List<String> ids=payments.stream().map(SPayment::merchantId).distinct().collect(Collectors.toList());
        Map<String,SMerchant> byId=mr.findByIdIn(ids).stream().collect(Collectors.toMap(SMerchant::id,m->m));
        return payments.stream().collect(Collectors.toMap(p->p,p->byId.getOrDefault(p.merchantId(),new SMerchant("?","Unknown"))));
    }
}

@SpringBootTest
class M27T3SynthesisTest{
    @Autowired SynthOrderController ctrl;
    @Autowired SPaymentRepo pr;
    @Autowired SMerchantRepo mr;

    @Test void threeOrders(){assertEquals(3,ctrl.orders().size());}
    @Test void payments_batchedOneQuery(){
        ctrl.payments(ctrl.orders());
        assertEquals(1,pr.q.get());
    }
    @Test void merchants_batchedOneQuery(){
        var orders=ctrl.orders();
        var payments=ctrl.payments(orders);
        var allPayments=payments.values().stream().flatMap(Collection::stream).collect(Collectors.toList());
        ctrl.merchant(allPayments);
        assertEquals(1,mr.q.get());
    }
    @Test void totalQueries_isThree(){
        var orders=ctrl.orders();
        var payments=ctrl.payments(orders);
        var allP=payments.values().stream().flatMap(Collection::stream).collect(Collectors.toList());
        ctrl.merchant(allP);
        assertEquals(1,pr.q.get(),"payments: 1 batch query");
        assertEquals(1,mr.q.get(),"merchants: 1 batch query");
        // Plus 1 for orders = 3 total (vs 1+3×2+6×2=19 naive)
    }
}
